import { ArrowUpRight, CheckCircle } from "lucide-react";
import type { Metadata } from "next";
import { Link } from "@/components/primitives/link";
import { Button, buttonVariants } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { CopyButton } from "@/components/ui/copy-button";
import { ConfettiSideCannons } from "@/components/ui/magicui/confetti/confetti-side-cannons";
import { constructMetadata } from "@/config/metadata";
import { routes } from "@/config/routes";
import { saveVercelDeployment } from "@/server/services/vercel";

export const metadata: Metadata = constructMetadata({
  title: "Deployment Successful",
  description: "Your project has been successfully deployed to Vercel.",
  noIndex: true,
});

interface DeploymentInfo {
  teamId: string | undefined;
  projectId: string | undefined;
  deploymentId: string | undefined;
  deploymentDashboardUrl: string;
  deploymentUrl: string;
  productionDeployHookUrl: string;
  projectDashboardUrl: string;
  projectName: string;
  repositoryUrl: string;
}

function extractDeploymentInfo(
  searchParams: Record<string, string | string[] | undefined>
): DeploymentInfo {
  const teamId = typeof searchParams.teamId === "string" ? searchParams.teamId : undefined;
  const projectId = typeof searchParams.projectId === "string" ? searchParams.projectId : undefined;
  const deploymentId =
    typeof searchParams.deploymentId === "string" ? searchParams.deploymentId : undefined;

  function decodeParam(param: string | string[] | undefined): string {
    if (typeof param === "string") {
      return decodeURIComponent(param);
    }
    return "";
  }

  return {
    teamId,
    projectId,
    deploymentId,
    deploymentDashboardUrl: decodeParam(searchParams["deployment-dashboard-url"]),
    deploymentUrl: decodeParam(searchParams["deployment-url"]),
    productionDeployHookUrl: decodeParam(searchParams["production-deploy-hook-url"]),
    projectDashboardUrl: decodeParam(searchParams["project-dashboard-url"]),
    projectName: decodeParam(searchParams["project-name"]),
    repositoryUrl: decodeParam(searchParams["repository-url"]),
  };
}

export default async function VercelDeployPage({
  searchParams,
}: {
  searchParams: Promise<Record<string, string | string[] | undefined>>;
}) {
  const params = await searchParams;
  const deploymentInfo = extractDeploymentInfo(params);

  // Attempt to save deployment info to the database
  await saveVercelDeployment(deploymentInfo);

  return (
    <>
      <ConfettiSideCannons />
      <div className="container max-w-2xl mx-auto py-10">
        <Card>
          <CardHeader className="text-center">
            <div className="mx-auto w-12 h-12 rounded-full bg-green-100 dark:bg-green-900 flex items-center justify-center mb-4">
              <CheckCircle className="w-6 h-6 text-green-600 dark:text-green-400" />
            </div>
            <CardTitle className="text-2xl">Deployment Successful!</CardTitle>
            <CardDescription>
              Your project {deploymentInfo.projectName} has been successfully deployed to Vercel
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="space-y-2">
              <h3 className="text-sm font-medium">Deployment URLs</h3>
              <div className="grid gap-2">
                <Link href={deploymentInfo.deploymentUrl} className="text-sm underline">
                  View Live Site →
                </Link>
                <Link href={deploymentInfo.deploymentDashboardUrl} className="text-sm underline">
                  View Deployment on Vercel →
                </Link>
              </div>
            </div>

            <div className="space-y-2">
              <h3 className="text-sm font-medium">Project Information</h3>
              <div className="grid gap-2">
                <Link href={deploymentInfo.projectDashboardUrl} className="text-sm underline">
                  View Project on Vercel →
                </Link>
                <Link href={deploymentInfo.repositoryUrl} className="text-sm underline">
                  GitHub Repository →
                </Link>
                <div className="flex items-center space-x-2 bg-muted p-2 rounded-md">
                  <code className="text-sm flex-grow overflow-x-auto">
                    git clone {deploymentInfo.repositoryUrl}
                  </code>
                  <CopyButton
                    value={`git clone ${deploymentInfo.repositoryUrl}`}
                    successTitle="Command copied!"
                    className="h-6 w-6"
                  />
                </div>
              </div>
            </div>
          </CardContent>
          <CardFooter className="flex justify-center gap-4">
            <Link
              className={buttonVariants({ variant: "default" })}
              href={deploymentInfo.deploymentUrl}
            >
              Visit Site <ArrowUpRight className="w-4 h-4" />
            </Link>
            <Button asChild variant="outline">
              <Link href={routes.app.dashboard}>Shipkit Dashboard</Link>
            </Button>
          </CardFooter>
        </Card>
      </div>
    </>
  );
}

import { and, eq } from "drizzle-orm";
import type { NextRequest } from "next/server";
import { NextResponse } from "next/server";
import { BASE_URL } from "@/config/base-url";
import { routes } from "@/config/routes";
import { STATUS_CODES } from "@/config/status-codes";
import { env } from "@/env";
import { routeRedirect } from "@/lib/utils/redirect";
import { auth } from "@/server/auth";
import { db } from "@/server/db";
import { accounts } from "@/server/db/schema";

interface RouteContext {
  params: Promise<{
    path?: string[];
  }>;
}

export async function GET(request: NextRequest, context: RouteContext) {
  console.log("[Vercel OAuth] Callback hit", { url: request.url });

  if (!env.NEXT_PUBLIC_FEATURE_VERCEL_INTEGRATION_ENABLED) {
    console.log("[Vercel OAuth] Feature flag disabled, redirecting to /");
    return NextResponse.redirect(new URL("/", request.url));
  }

  try {
    const session = await auth();
    console.log("[Vercel OAuth] Session check", {
      hasUser: !!session?.user,
      userId: session?.user?.id,
    });

    if (!session?.user) {
      return NextResponse.redirect(new URL(routes.auth.signIn, request.url));
    }

    // Await the params Promise
    const resolvedParams = await context.params;
    // Determine the base path for redirection from the dynamic route parameter
    const pathSegments = resolvedParams.path;
    let redirectBasePath = routes.settings.account; // Default

    if (pathSegments && pathSegments.length > 0) {
      const decodedPath = pathSegments.map(decodeURIComponent).join("/");
      // Ensure the path starts with a slash
      redirectBasePath = decodedPath.startsWith("/") ? decodedPath : `/${decodedPath}`;
    }

    // Helper function to construct redirect URLs
    const constructRedirectUrl = (params: Record<string, string>) => {
      const url = new URL(redirectBasePath, request.url);
      for (const [key, value] of Object.entries(params)) {
        url.searchParams.set(key, value);
      }
      return url;
    };

    const { searchParams } = new URL(request.url);
    const code = searchParams.get("code");
    const state = searchParams.get("state");
    const error = searchParams.get("error");
    const configurationId = searchParams.get("configurationId");
    const teamId = searchParams.get("teamId");

    // Log all parameters for debugging
    console.log("Vercel OAuth callback parameters:", {
      code: code ? "present" : "missing",
      state,
      error,
      configurationId,
      teamId,
      allParams: Object.fromEntries(searchParams.entries()),
    });

    if (error) {
      console.error("Error in Vercel OAuth callback:", error);
      // Use dynamic redirect path for error
      return NextResponse.redirect(constructRedirectUrl({ code: "VERCEL_CONNECTION_FAILED" }));
    }

    // CRITICAL: Validate CSRF token
    // Since sessionStorage is client-side only, we need to pass the state through cookies
    // Get the stored state from cookie instead
    const cookieStore = request.cookies;
    const storedState = cookieStore.get("vercel_oauth_state")?.value;

    if (!state || !storedState || state !== storedState) {
      console.error("[Vercel OAuth] CSRF validation failed:", {
        stateFromQuery: state ?? "missing",
        stateFromCookie: storedState ?? "missing",
        cookiesPresent: request.cookies.getAll().map((c) => c.name),
      });
      return NextResponse.redirect(constructRedirectUrl({ code: "VERCEL_CONNECTION_FAILED" }));
    }

    if (!code) {
      console.error("No code provided in Vercel OAuth callback");
      // Use dynamic redirect path for error
      return NextResponse.redirect(constructRedirectUrl({ code: "VERCEL_CONNECTION_FAILED" }));
    }

    // Validate required credentials before attempting token exchange
    const clientId = env.VERCEL_CLIENT_ID;
    const clientSecret = env.VERCEL_CLIENT_SECRET;

    if (!clientId || !clientSecret) {
      console.error("[Vercel OAuth] Missing VERCEL_CLIENT_ID or VERCEL_CLIENT_SECRET env vars");
      return NextResponse.redirect(constructRedirectUrl({ code: "VERCEL_CONNECTION_FAILED" }));
    }

    // The redirect_uri MUST match the Redirect URL configured in the Vercel Integration Console
    // Use BASE_URL (canonical production URL) rather than request.url.origin to ensure consistency
    const vercelCallbackUri = `${BASE_URL}/connect/vercel/auth`;

    console.log("[Vercel OAuth] Token exchange", {
      baseUrl: BASE_URL,
      requestOrigin: new URL(request.url).origin,
      vercelCallbackUri,
    });

    // Exchange code for access token
    const tokenResponse = await fetch("https://api.vercel.com/v2/oauth/access_token", {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams({
        code,
        client_id: clientId,
        client_secret: clientSecret,
        redirect_uri: vercelCallbackUri,
      }),
    });

    if (!tokenResponse.ok) {
      const errorText = await tokenResponse.text();
      console.error("[Vercel OAuth] Token exchange failed:", {
        status: tokenResponse.status,
        statusText: tokenResponse.statusText,
        body: errorText,
        redirectUri: vercelCallbackUri,
      });
      return NextResponse.redirect(constructRedirectUrl({ code: "VERCEL_CONNECTION_FAILED" }));
    }

    const tokenData = await tokenResponse.json();
    console.log("[Vercel OAuth] Token exchange successful");

    const { access_token, refresh_token, expires_in, team_id } = tokenData;

    // Get user info from Vercel
    const userResponse = await fetch("https://api.vercel.com/v2/user", {
      headers: {
        Authorization: `Bearer ${access_token}`,
      },
    });

    if (!userResponse.ok) {
      console.error("Failed to get user info from Vercel");
      // Use dynamic redirect path for error
      return NextResponse.redirect(constructRedirectUrl({ code: "VERCEL_CONNECTION_FAILED" }));
    }

    const userData = await userResponse.json();
    console.log("User info retrieved:", {
      hasUserId: !!(userData.user?.id || userData.user?.uid),
      user: userData.user
        ? {
            id: userData.user.id || userData.user.uid,
            email: userData.user.email,
            username: userData.user.username,
            name: userData.user.name,
          }
        : null,
    });

    const vercelUserId = userData.user?.id || userData.user?.uid;

    if (!vercelUserId) {
      console.error("Failed to get Vercel user ID");
      // Use dynamic redirect path for error
      return NextResponse.redirect(constructRedirectUrl({ code: "VERCEL_CONNECTION_FAILED" }));
    }

    // Calculate token expiry date - default to 30 days if expires_in is not provided
    let expiresAt = null;
    if (expires_in) {
      expiresAt = new Date();
      expiresAt.setSeconds(expiresAt.getSeconds() + expires_in);
      expiresAt = Math.floor(expiresAt.getTime() / 1000); // Convert to Unix timestamp
    } else {
      // Default to 30 days if expires_in is not provided
      expiresAt = Math.floor(Date.now() / 1000) + 30 * 24 * 60 * 60;
    }

    // Store the access token and user info in the database
    try {
      if (!db) {
        console.error("Database not initialized - cannot save Vercel connection");
        return routeRedirect(routes.settings.account, {
          code: STATUS_CODES.CONNECT_VERCEL_ERROR.code,
          nextUrl: request.url,
          request: request,
        });
      }

      // First, check if this Vercel account (by providerAccountId) already exists
      const existingAccount = await db
        .select()
        .from(accounts)
        .where(and(eq(accounts.provider, "vercel"), eq(accounts.providerAccountId, vercelUserId)))
        .limit(1);

      if (existingAccount && existingAccount.length > 0) {
        // If exists, update instead of insert
        await db
          .update(accounts)
          .set({
            userId: session.user.id, // Update to current user if account exists but belongs to another user
            access_token,
            refresh_token,
            expires_at: expiresAt,
            token_type: "bearer",
            scope: "user team",
          })
          .where(
            and(eq(accounts.provider, "vercel"), eq(accounts.providerAccountId, vercelUserId))
          );

        console.log("Updated existing Vercel account for user:", session.user.id);
      } else {
        // Delete any existing Vercel connections for this user (different providerAccountId)
        await db
          .delete(accounts)
          .where(and(eq(accounts.provider, "vercel"), eq(accounts.userId, session.user.id)));

        // Insert new account
        await db.insert(accounts).values({
          userId: session.user.id,
          type: "oauth",
          provider: "vercel",
          providerAccountId: vercelUserId,
          access_token,
          refresh_token,
          expires_at: expiresAt,
          token_type: "bearer",
          scope: "user team",
          id_token: null,
          session_state: null,
        });

        console.log("Inserted new Vercel account for user:", session.user.id);
      }
    } catch (dbError) {
      console.error("Database error handling Vercel account:", dbError);
      throw dbError;
    }

    console.log("Account data stored in database for user:", session.user.id);

    // Try to update the session directly - this won't always work in a server route
    // but can help in some cases by signaling the auth system that accounts have changed
    try {
      const { update } = await import("@/server/auth");
      await update({
        user: {
          accounts: [{ provider: "vercel", providerAccountId: vercelUserId }],
        },
      });
      console.log("Auth session updated with Vercel account");
    } catch (error) {
      console.warn("Could not update session directly:", error);
      // This is non-fatal, the UI will handle updating via updateSession
    }

    // Redirect back using the dynamic path with success message and clear CSRF cookie
    const successResponse = NextResponse.redirect(
      constructRedirectUrl({ code: STATUS_CODES.CONNECT_VERCEL.code })
    );
    successResponse.cookies.delete("vercel_oauth_state");
    return successResponse;
  } catch (error) {
    console.error("Error in Vercel OAuth callback:", error);
    // Await the params Promise in catch block as well
    const resolvedParams = await context.params;
    // Determine the base path for redirection even in the catch block
    const pathSegments = resolvedParams.path;
    let redirectBasePath = routes.settings.account; // Default
    if (pathSegments && pathSegments.length > 0) {
      const decodedPath = pathSegments.map(decodeURIComponent).join("/");
      redirectBasePath = decodedPath.startsWith("/") ? decodedPath : `/${decodedPath}`;
    }
    const errorUrl = new URL(redirectBasePath, request.url);
    errorUrl.searchParams.set("code", "VERCEL_ERROR");
    return NextResponse.redirect(errorUrl);
  }
}

import { headers } from "next/headers";
import type { NextRequest } from "next/server";

/*
 * Vercel Webhook Handler
 * @see https://vercel.com/docs/observability/webhooks-overview
 *
 * This endpoint receives and logs all webhook events from Vercel.
 * It's useful for debugging and understanding the webhook payload structure.
 */

export const dynamic = "force-dynamic"; // Disable caching for webhook endpoint

export async function POST(request: NextRequest) {
  // console.log({
  // 	message: "Vercel webhook received",
  // 	url: request.url,
  // 	method: request.method,
  // 	headers: Object.fromEntries(request.headers.entries()),
  // });

  try {
    // Get headers including Vercel's signature
    const headersList = await headers();
    const signature = headersList.get("x-vercel-signature");
    const timestamp = headersList.get("x-vercel-timestamp");

    // Parse the request body
    const body = await request.json();

    // Log all the information we received
    console.log({
      event: "Vercel Webhook Received",
      timestamp: new Date().toISOString(),
      headers: {
        signature,
        timestamp,
        // Log other relevant headers
        type: headersList.get("x-vercel-event"),
        id: headersList.get("x-vercel-id"),
      },
      body, // Log the entire webhook payload
    });

    // Return a success response
    return new Response(JSON.stringify({ received: true }), {
      status: 200,
      headers: {
        "Content-Type": "application/json",
      },
    });
  } catch (error) {
    // Log any errors that occur
    console.error("Error processing Vercel webhook:", error);

    // Return an error response
    return new Response(JSON.stringify({ error: "Failed to process webhook" }), {
      status: 500,
      headers: {
        "Content-Type": "application/json",
      },
    });
  }
}

import { env } from "@/env";
import { getPayloadClient } from "@/lib/payload/payload";
import type { VercelDeployment } from "@/payload-types"; // Assuming payload-types are generated

interface DeploymentInfo {
  teamId: string | undefined;
  projectId: string | undefined;
  deploymentId: string | undefined;
  deploymentDashboardUrl: string;
  deploymentUrl: string;
  productionDeployHookUrl: string;
  projectDashboardUrl: string;
  projectName: string;
  repositoryUrl: string;
}

/**
 * Saves Vercel deployment information to the Payload CMS database.
 * Checks for existing deployment ID to prevent duplicates.
 * @param deploymentInfo - The deployment details extracted from Vercel redirect.
 * @returns Promise<VercelDeployment | null> - The created deployment record or null if failed/skipped.
 */
export async function saveVercelDeployment(deploymentInfo: DeploymentInfo) {
  if (!env.NEXT_PUBLIC_FEATURE_PAYLOAD_ENABLED) {
    console.warn("Payload not enabled, skipping Vercel deployment save.");
    return null;
  }

  if (!deploymentInfo.deploymentId || !deploymentInfo.projectId) {
    console.error(
      "Missing required deployment information (deploymentId or projectId), cannot save Vercel deployment info."
    );
    return null;
  }

  try {
    const payload = await getPayloadClient();
    if (!payload) {
      console.error("Failed to get Payload client, cannot save Vercel deployment info.");
      return null;
    }

    // Check if a deployment with this ID already exists
    const existing = await payload.find({
      collection: "vercel-deployments",
      where: {
        deploymentId: {
          equals: deploymentInfo.deploymentId,
        },
      },
      limit: 1,
    });

    if (existing.docs.length > 0) {
      return existing.docs[0]; // Return the existing one
    }

    // Create new deployment record
    const newDeployment = await payload.create({
      collection: "vercel-deployments",
      data: {
        teamId: deploymentInfo.teamId,
        projectId: deploymentInfo.projectId,
        deploymentId: deploymentInfo.deploymentId,
        deploymentDashboardUrl: deploymentInfo.deploymentDashboardUrl,
        deploymentUrl: deploymentInfo.deploymentUrl,
        productionDeployHookUrl: deploymentInfo.productionDeployHookUrl,
        projectDashboardUrl: deploymentInfo.projectDashboardUrl,
        projectName: deploymentInfo.projectName,
        repositoryUrl: deploymentInfo.repositoryUrl,
      },
    });

    return newDeployment;
  } catch (error) {
    console.error("Error saving Vercel deployment info:", error);
    return null;
  }
}

import { and, eq } from "drizzle-orm";
import { logger } from "@/lib/logger";
import { db } from "@/server/db";
import { accounts } from "@/server/db/schema";

/**
 * Check if a user has connected their Vercel account
 *
 * @param userId The ID of the user to check
 * @returns True if the user has connected their Vercel account, false otherwise
 */
export async function checkVercelConnection(userId: string): Promise<boolean> {
  logger.info("Checking Vercel connection", { userId });

  if (!userId) {
    logger.warn("No user ID provided for Vercel connection check");
    return false;
  }

  try {
    const vercelAccount = await db?.query.accounts.findFirst({
      where: and(eq(accounts.userId, userId), eq(accounts.provider, "vercel")),
    });

    const hasVercelConnection = !!vercelAccount;

    logger.info("Vercel connection status", {
      userId,
      hasVercelConnection,
    });

    return hasVercelConnection;
  } catch (error) {
    logger.error("Error checking Vercel connection", {
      userId,
      error: error instanceof Error ? error.message : "Unknown error",
    });
    return false;
  }
}

/**
 * Get the Vercel account for a user
 *
 * @param userId The ID of the user
 * @returns The Vercel account for the user, or null if not connected
 */
export async function getVercelAccount(userId: string) {
  logger.info("Getting Vercel account", { userId });

  if (!userId) {
    logger.warn("No user ID provided for Vercel account");
    return null;
  }

  try {
    const vercelAccount = await db?.query.accounts.findFirst({
      where: and(eq(accounts.userId, userId), eq(accounts.provider, "vercel")),
    });

    if (!vercelAccount) {
      logger.info("No Vercel account found for user", { userId });
      return null;
    }

    logger.info("Vercel account found for user", { userId });
    return vercelAccount;
  } catch (error) {
    logger.error("Error getting Vercel account", {
      userId,
      error: error instanceof Error ? error.message : "Unknown error",
    });
    return null;
  }
}

/**
 * Get the Vercel access token for a user
 *
 * @param userId The ID of the user
 * @returns The Vercel access token for the user, or null if not connected
 */
export async function getVercelAccessToken(userId: string): Promise<string | null> {
  logger.info("Getting Vercel access token", { userId });

  if (!userId) {
    logger.warn("No user ID provided for Vercel access token");
    return null;
  }

  try {
    const vercelAccount = await getVercelAccount(userId);

    if (!vercelAccount?.access_token) {
      logger.info("No Vercel access token found for user", { userId });
      return null;
    }

    // Check if token is expired
    if (vercelAccount.expires_at) {
      const now = Math.floor(Date.now() / 1000);
      if (vercelAccount.expires_at < now) {
        logger.warn("Vercel access token has expired", {
          userId,
          expiresAt: vercelAccount.expires_at,
          now,
        });
        return null;
      }
    }

    logger.info("Vercel access token retrieved for user", { userId });
    return vercelAccount.access_token;
  } catch (error) {
    logger.error("Error getting Vercel access token", {
      userId,
      error: error instanceof Error ? error.message : "Unknown error",
    });
    return null;
  }
}

/**
 * Vercel API Integration Service
 * Handles automated project creation and deployment configuration
 */

export interface VercelConfig {
  accessToken: string;
  teamId?: string;
}

export interface VercelProjectConfig {
  name: string;
  gitRepository?: {
    type: "github" | "gitlab" | "bitbucket";
    repo: string; // e.g., "username/repo-name"
  };
  framework?: string;
  buildCommand?: string;
  outputDirectory?: string;
  installCommand?: string;
  devCommand?: string;
  environmentVariables?: {
    key: string;
    value: string;
    target: readonly ("production" | "preview" | "development")[];
  }[];
  domains?: string[];
}

export interface VercelProjectResult {
  success: boolean;
  projectId?: string;
  projectUrl?: string;
  deploymentUrl?: string;
  error?: string;
  details?: any;
}

export interface VercelDeploymentResult {
  success: boolean;
  deploymentId?: string;
  deploymentUrl?: string;
  error?: string;
  details?: any;
}

export class VercelAPIService {
  private baseUrl = "https://api.vercel.com";
  private accessToken: string;
  private teamId?: string;

  constructor(config: VercelConfig) {
    this.accessToken = config.accessToken;
    this.teamId = config.teamId;
  }

  /**
   * Create a new Vercel project from a Git repository
   */
  async createProject(config: VercelProjectConfig): Promise<VercelProjectResult> {
    try {
      console.log(`Creating Vercel project: ${config.name}`);

      const projectData: any = {
        name: config.name,
        framework: this.detectFramework(config.framework),
      };

      // Only add gitRepository if provided
      if (config.gitRepository) {
        projectData.gitRepository = {
          type: config.gitRepository.type,
          repo: config.gitRepository.repo,
        };
      }

      // Only add optional fields if they are provided
      if (config.buildCommand) projectData.buildCommand = config.buildCommand;
      if (config.outputDirectory) projectData.outputDirectory = config.outputDirectory;
      if (config.installCommand) projectData.installCommand = config.installCommand;
      if (config.devCommand) projectData.devCommand = config.devCommand;

      // Handle environment variables
      if (config.environmentVariables && config.environmentVariables.length > 0) {
        projectData.environmentVariables = config.environmentVariables.map((env) => ({
          key: env.key,
          value: env.value,
          type: "encrypted" as const,
          target: Array.isArray(env.target) ? env.target : [env.target],
        }));
      }

      // Log the request payload for debugging
